//! Emoji annotation data derived from Unicode CLDR.
//! Generated from CLDR annotations/en.xml and annotationsDerived/en.xml.
//! Do not edit manually — regenerate with scripts/gen_emoji_data.py.
//!
//! PHF maps generated by build.rs from src/tables/data/emoji_*.tsv.

// Single-codepoint emoji to short name (1727 entries).
include!(concat!(env!("OUT_DIR"), "/emoji_single_phf.rs"));

// Multi-codepoint emoji sequences to short name (2553 entries).
// Key format: codepoints as uppercase hex separated by underscores.
include!(concat!(env!("OUT_DIR"), "/emoji_multi_phf.rs"));

// Codepoints that can begin a multi-codepoint emoji sequence (188 entries).
include!(concat!(env!("OUT_DIR"), "/emoji_starters_phf.rs"));

/// Maximum length of any multi-codepoint emoji sequence.
pub const MAX_EMOJI_SEQ_LEN: usize = 9;
